### `src/middleware/auth.js`
```javascript
const crypto = require('crypto');

/**
 * Verifies the authentication data received from the Telegram Web App.
 * @see https://core.telegram.org/bots/webapps#validating-data-received-via-the-web-app
 */
const verifyTelegramAuth = (req, res, next) => {
    const authHeader = req.headers.authorization;

    if (!authHeader || !authHeader.startsWith('tma ')) {
        return res.status(401).json({ error: 'Unauthorized: Missing or invalid authorization header.' });
    }

    const initData = authHeader.split(' ')[1];

    try {
        const urlParams = new URLSearchParams(initData);
        const hash = urlParams.get('hash');

        if (!hash) {
            return res.status(401).json({ error: 'Unauthorized: Hash not found in initData.' });
        }

        urlParams.delete('hash');
        const dataCheckArr = [];
        urlParams.sort(); // Keys must be sorted alphabetically
        urlParams.forEach((val, key) => dataCheckArr.push(`${key}=${val}`));

        const dataCheckString = dataCheckArr.join('\n');

        const secretKey = crypto.createHmac('sha256', 'WebAppData').update(process.env.TELEGRAM_BOT_TOKEN).digest();
        const calculatedHash = crypto.createHmac('sha256', secretKey).update(dataCheckString).digest('hex');

        if (calculatedHash === hash) {
            // Authentication successful. Attach user data to the request object.
            req.user = JSON.parse(urlParams.get('user'));
            next();
        } else {
            return res.status(401).json({ error: 'Unauthorized: Invalid hash.' });
        }
    } catch (error) {
        return res.status(400).json({ error: 'Bad Request: Invalid initData format.', details: error.message });
    }
};

module.exports = { verifyTelegramAuth };
```

### `src/routes/agents.js`
```javascript
const express = require('express');
const router = express.Router();

// Mock agent data store
const agents = {
    "NOVA": { status: "active", tasks: 2 },
    "LUCA": { status: "in_progress", tasks: 1 },
    "PICO": { status: "review", tasks: 3 },
    "LILY": { status: "inactive", tasks: 0 }
};

/**
 * @route   GET /api/v1/agents/:agentId/status
 * @desc    Get the status of a specific agent
 * @access  Private (Requires Telegram Auth)
 */
router.get('/:agentId/status', (req, res) => {
    const { agentId } = req.params;
    const agent = agents[agentId.toUpperCase()];

    if (!agent) {
        return res.status(404).json({ error: `Agent with ID '${agentId}' not found.` });
    }

    res.status(200).json({
        agentId: agentId.toUpperCase(),
        status: agent.status,
        activeTasks: agent.tasks,
        timestamp: new Date().toISOString(),
        authenticatedUser: req.user // User data from the auth middleware
    });
});

module.exports = router;
```

### `src/index.js`
```javascript
require('dotenv').config();
const express = require('express');
const { verifyTelegramAuth } = require('./middleware/auth');
const agentRoutes = require('./routes/agents');

// Check for required environment variables
if (!process.env.TELEGRAM_BOT_TOKEN) {
    console.error("FATAL ERROR: TELEGRAM_BOT_TOKEN is not defined.");
    process.exit(1);
}

const app = express();
const PORT = process.env.PORT || 3000;

// Middleware
app.use(express.json()); // for parsing application/json

// Health check endpoint
app.get('/health', (req, res) => {
    res.status(200).send('OK');
});

// Main API routes with Telegram authentication
app.use('/api/v1/agents', verifyTelegramAuth, agentRoutes);

// Global error handler for unhandled routes
app.use((req, res) => {
    res.status(404).json({ error: 'Not Found' });
});

app.listen(PORT, () => {
    console.log(`MyCrew API Server is running on port ${PORT}`);
});
```
